import React, { useState, useEffect } from 'react';
import { partnerService } from '../services/api';
import { TrendingUp, DollarSign, ShoppingCart, Package, Users, Award } from 'lucide-react';

function PartnerDashboardNew() {
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    loadDashboard();
  }, []);

  const loadDashboard = async () => {
    try {
      setLoading(true);
      setError('');
      const response = await partnerService.getDashboard();
      console.log('📊 Partner Dashboard Data:', response.data);
      setStats(response.data);
    } catch (error) {
      console.error('❌ Dashboard error:', error);
      setError(error.response?.data?.message || 'Failed to load dashboard');
